import{_ as i,o as l,c as s,a2 as n}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"启发式评估","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/03-validation/04-heuristic-evaluation.md","filePath":"03-interaction-design/notes/03-validation/04-heuristic-evaluation.md","lastUpdated":null}'),e={name:"03-interaction-design/notes/03-validation/04-heuristic-evaluation.md"};function t(r,a,h,p,o,d){return l(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="启发式评估" tabindex="-1">启发式评估 <a class="header-anchor" href="#启发式评估" aria-label="Permalink to &quot;启发式评估&quot;">​</a></h1><p>启发式评估由一名或多名检查者依据明确的可用性原则，独立检查界面并记录潜在问题，再合并、去重和评定影响。它是一种检查方法，能在没有招募用户时发现问题线索，但不能替代真实任务观察、无障碍合规评估或工程验证。</p><h2 id="方法的输入与输出" tabindex="-1">方法的输入与输出 <a class="header-anchor" href="#方法的输入与输出" aria-label="Permalink to &quot;方法的输入与输出&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>明确产品范围、版本和平台；</li><li>目标角色、任务、数据和环境；</li><li>适用启发式集合及定义；</li><li>可运行产品或覆盖关键状态的原型；</li><li>业务、权限和安全规则；</li><li>问题记录与严重性规则。</li></ul><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><ul><li>可复现问题清单；</li><li>触发条件、证据、任务影响与相关原则；</li><li>严重性和证据强度；</li><li>去重后的机制分组；</li><li>修复候选、验证步骤和未覆盖范围。</li></ul><p>评估输出不是“合格/不合格”总分。单个检查者会漏掉大量问题，原始研究显示汇总多名检查者能提高覆盖；具体人数不是对所有项目的保证。</p><h2 id="标准流程" tabindex="-1">标准流程 <a class="header-anchor" href="#标准流程" aria-label="Permalink to &quot;标准流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S[&quot;确定范围、任务与原则&quot;] --&gt; B[&quot;建立基线和测试数据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; I[&quot;检查者独立走查&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; R[&quot;记录事实、影响与原则&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; M[&quot;合并、去重与讨论&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M --&gt; P[&quot;评定严重性和证据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; V[&quot;修复并执行任务复测&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>独立检查可以减少互相暗示；合并阶段再讨论相同机制和分歧。个人学习只有一名检查者时，可按不同角色、输入方式和时间分轮检查，并明确覆盖有限。</p><h2 id="选择启发式集合" tabindex="-1">选择启发式集合 <a class="header-anchor" href="#选择启发式集合" aria-label="Permalink to &quot;选择启发式集合&quot;">​</a></h2><p>Nielsen 的十条启发式适合作为通用起点：系统状态、现实匹配、用户控制、一致性、错误预防、识别、效率、简洁、错误恢复、帮助。它们是广泛经验原则，不是规范性标准。</p><p>高风险或特殊领域需要增加检查项：</p><ul><li>金融：金额、收款人、授权、幂等、对账与退款；</li><li>医疗：身份、单位、版本、警告与审计；</li><li>协作：权限、并发、通知、归属和冲突；</li><li>AI：输入边界、输出不确定性、引用、复核与失败；</li><li>Web 可访问性：另按 WCAG 和实际辅助技术评估。</li></ul><p>不要随意改写原则后仍声称使用原始量表。记录使用的版本和自定义项。</p><h2 id="确定范围与样本" tabindex="-1">确定范围与样本 <a class="header-anchor" href="#确定范围与样本" aria-label="Permalink to &quot;确定范围与样本&quot;">​</a></h2><h3 id="代表性页面与状态" tabindex="-1">代表性页面与状态 <a class="header-anchor" href="#代表性页面与状态" aria-label="Permalink to &quot;代表性页面与状态&quot;">​</a></h3><p>覆盖高频、高风险、关键入口、模板页面、复杂组件和已知问题。每个页面至少检查相关的加载、空、成功、失败、权限和响应式状态。</p><h3 id="任务优先" tabindex="-1">任务优先 <a class="header-anchor" href="#任务优先" aria-label="Permalink to &quot;任务优先&quot;">​</a></h3><p>按完整任务走查比逐页浏览更容易发现跨页面与状态问题。任务应有固定输入和完成标准，不向检查者泄露按钮路径。</p><h3 id="设备与输入" tabindex="-1">设备与输入 <a class="header-anchor" href="#设备与输入" aria-label="Permalink to &quot;设备与输入&quot;">​</a></h3><p>至少按产品支持范围选择桌面、窄屏、键盘和辅助技术。静态截图不足以评估动态状态、焦点、等待和恢复。</p><h2 id="两轮检查" tabindex="-1">两轮检查 <a class="header-anchor" href="#两轮检查" aria-label="Permalink to &quot;两轮检查&quot;">​</a></h2><h3 id="第一轮-理解整体" tabindex="-1">第一轮：理解整体 <a class="header-anchor" href="#第一轮-理解整体" aria-label="Permalink to &quot;第一轮：理解整体&quot;">​</a></h3><p>执行端到端任务，理解对象、流程、术语与主要状态，不急于记录每个微小问题。</p><h3 id="第二轮-逐原则检查" tabindex="-1">第二轮：逐原则检查 <a class="header-anchor" href="#第二轮-逐原则检查" aria-label="Permalink to &quot;第二轮：逐原则检查&quot;">​</a></h3><p>对每一步询问：</p><ul><li>系统状态是否准确可感知？</li><li>对象和动作是否与任务语言匹配？</li><li>能否取消、返回、撤销和恢复？</li><li>相同功能是否一致并符合平台约定？</li><li>错误是否被预防、识别和修正？</li><li>是否要求记住不必要信息？</li><li>是否同时支持初次与重复任务？</li><li>信息是否与当前决策相关？</li><li>帮助是否可找到且不替代界面修复？</li></ul><h2 id="问题记录格式" tabindex="-1">问题记录格式 <a class="header-anchor" href="#问题记录格式" aria-label="Permalink to &quot;问题记录格式&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ID：HE-001</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 上下文：版本、角色、设备、对象状态</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 任务与步骤：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 复现：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 事实：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 相关启发式：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 用户/业务影响：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 严重性依据：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 证据：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原因推断与未知：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复候选：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 验证标准：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>标题应描述机制和结果，如“保存期间无反馈导致重复创建”，不要只写“违反系统状态可见”。</p><h2 id="严重性" tabindex="-1">严重性 <a class="header-anchor" href="#严重性" aria-label="Permalink to &quot;严重性&quot;">​</a></h2><p>分别评估：</p><ul><li>任务是否还能完成；</li><li>发生条件和影响范围；</li><li>用户能否发现并自行恢复；</li><li>数据、资金、隐私、安全和法律后果；</li><li>问题是否重复出现；</li><li>证据是当前复现还是推断。</li></ul><p>可以使用团队量表，但每一级必须有定义。严重性不是优先级，后者还涉及修复成本、依赖和时间。</p><h2 id="合并与去重" tabindex="-1">合并与去重 <a class="header-anchor" href="#合并与去重" aria-label="Permalink to &quot;合并与去重&quot;">​</a></h2><p>当问题具有相同触发、机制和影响时合并，即使检查者引用不同启发式。保留所有证据与影响场景。若只是表面相似但根因不同，例如“按钮不可用”分别由权限与请求故障造成，应分开。</p><p>分歧处理：</p><ol><li>回到产品复现和任务结果；</li><li>查业务、平台或可访问性规则；</li><li>无法确认则记录为未知，不用多数投票替代证据；</li><li>建立下一步测试。</li></ol><h2 id="完整案例-项目删除流程评估" tabindex="-1">完整案例：项目删除流程评估 <a class="header-anchor" href="#完整案例-项目删除流程评估" aria-label="Permalink to &quot;完整案例：项目删除流程评估&quot;">​</a></h2><h3 id="范围与输入" tabindex="-1">范围与输入 <a class="header-anchor" href="#范围与输入" aria-label="Permalink to &quot;范围与输入&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>产品：项目管理 Web build 2026.07.15</span></span>
<span class="line"><span>角色：项目管理员</span></span>
<span class="line"><span>对象：项目 P-204，含 12 名成员、80 个任务、3 个外部集成</span></span>
<span class="line"><span>设备：Chrome 1280×720；键盘；另测 320 CSS px</span></span>
<span class="line"><span>目标：安全删除测试项目并确认数据处理</span></span>
<span class="line"><span>完成：项目不可用；可恢复性、集成和审计结果明确</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="第一轮流程" tabindex="-1">第一轮流程 <a class="header-anchor" href="#第一轮流程" aria-label="Permalink to &quot;第一轮流程&quot;">​</a></h3><p>设置 → 危险区域 → 删除项目 → 输入项目名 → 确认 → 返回项目列表。成功后出现“项目已删除”Toast。</p><h3 id="第二轮发现" tabindex="-1">第二轮发现 <a class="header-anchor" href="#第二轮发现" aria-label="Permalink to &quot;第二轮发现&quot;">​</a></h3><p><strong>HE-001：影响范围不完整</strong></p><ul><li>事实：确认页只显示项目名，没有成员、任务、集成和恢复期限。</li><li>原则：现实匹配、错误预防、帮助恢复。</li><li>影响：管理员无法判断外部集成和数据是否永久删除。</li><li>严重性：高风险不可逆任务；证据为当前界面事实。</li></ul><p><strong>HE-002：按钮与结果术语冲突</strong></p><ul><li>事实：按钮写“永久删除”，帮助文档写项目进入回收站 30 天。</li><li>原则：一致性、现实匹配。</li><li>影响：用户可能误判可恢复性；实现结果需验证。</li></ul><p><strong>HE-003：焦点恢复不合理</strong></p><ul><li>事实：删除后路由到列表，焦点仍位于已卸载对话框元素，键盘下一次 Tab 从文档起点开始。</li><li>原则：系统状态、用户控制；同时需对照 WCAG 焦点顺序。</li><li>影响：键盘用户丢失上下文。</li></ul><p><strong>HE-004：结果过于短暂</strong></p><ul><li>事实：Toast 5 秒消失，项目列表无删除记录或撤销入口。</li><li>原则：系统状态、恢复。</li><li>影响：无法重新确认删除对象和恢复方式。</li></ul><h3 id="机制分组" tabindex="-1">机制分组 <a class="header-anchor" href="#机制分组" aria-label="Permalink to &quot;机制分组&quot;">​</a></h3><p>HE-001、HE-002、HE-004 共享“删除生命周期与结果表达不完整”，可以作为一个产品/交互主题处理；HE-003 是独立焦点实现问题。</p><h3 id="修复输出" tabindex="-1">修复输出 <a class="header-anchor" href="#修复输出" aria-label="Permalink to &quot;修复输出&quot;">​</a></h3><ol><li>用准确操作“将项目移到回收站”，显示 30 天恢复期限。</li><li>确认页列出对象名、成员、任务和集成影响；服务端重新验证权限与版本。</li><li>结果进入持久回收站详情，显示删除时间、恢复和永久删除规则。</li><li>删除后焦点进入结果标题；返回列表时进入列表标题或合理位置。</li><li>永久删除作为单独高风险任务，重新认证并显示不可恢复影响。</li></ol><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>权限提交前撤销：不删除，保留对话框上下文并说明。</li><li>某外部集成清理失败：项目状态与集成清理分别显示，支持追踪。</li><li>请求超时：先查询项目状态，避免重复删除或显示错误成功。</li><li>项目被他人更新：版本冲突时重新显示最新影响范围。</li></ul><h3 id="复测" tabindex="-1">复测 <a class="header-anchor" href="#复测" aria-label="Permalink to &quot;复测&quot;">​</a></h3><p>使用同一 P-204 克隆数据执行主路径与失败；检查回收站、数据库状态和审计记录；仅用键盘和屏幕阅读器完成；确认 320 CSS 像素和 200% 放大下影响信息可读。</p><h2 id="方法局限与补充" tabindex="-1">方法局限与补充 <a class="header-anchor" href="#方法局限与补充" aria-label="Permalink to &quot;方法局限与补充&quot;">​</a></h2><ul><li>检查者不能代表真实用户，应结合任务观察、支持问题或行为数据。</li><li>原则较宽，容易产生解释差异，需要具体复现和证据。</li><li>自动扫描不能执行启发式判断；它可以补充规则检测。</li><li>领域规则必须由对应专家与受控系统验证。</li><li>通过评估不意味着所有问题被发现。</li></ul><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>检查范围只写“整个产品”：选择代表任务、页面与状态。</li><li>检查者一边讨论一边走查：先独立，后合并。</li><li>为十条原则强行找十个问题：只记录可复现事实。</li><li>问题没有任务影响和修复验证。</li><li>把启发式严重性当发布优先级。</li><li>用评估代替 WCAG 合规、性能、安全和用户证据。</li><li>修复后只检查截图，没有执行完整任务与失败分支。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>固定范围、版本、角色、任务、输入、设备与完成标准。</li><li>选择并记录启发式集合与领域扩展。</li><li>准备可触发主路径与关键状态的测试数据。</li><li>检查者独立执行整体与逐原则两轮检查。</li><li>记录事实、影响、证据、推断和验证，不只写原则名。</li><li>合并、去重、评定严重性与证据强度。</li><li>对规范、安全和业务问题使用对应方法补证。</li><li>修复后用原任务、键盘、响应式和故障重新验证。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>对“邀请成员并分配角色”执行一次启发式评估。</p><p>完成时应满足：</p><ul><li>范围含版本、角色、5 个固定邮箱和权限条件；</li><li>覆盖输入、等待、部分成功、失败、重复和无权限；</li><li>至少两轮检查，问题由事实而非原则名开始；</li><li>每项有任务影响、严重性依据、证据和修复验证；</li><li>相同机制问题已去重，不强求十条原则全覆盖；</li><li>键盘、屏幕阅读器和窄屏单独验证；</li><li>报告明确未覆盖范围和不能推断的结论。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://doi.org/10.1145/97243.97281" target="_blank" rel="noreferrer">Nielsen、Molich：Heuristic Evaluation of User Interfaces（CHI 1990）</a>（访问日期：2026-07-17）</li><li><a href="https://www.nngroup.com/articles/how-to-conduct-a-heuristic-13-evaluation/" target="_blank" rel="noreferrer">Jakob Nielsen：How to Conduct a Heuristic Evaluation</a>（访问日期：2026-07-17）</li><li><a href="https://www.nngroup.com/articles/ten-usability-heuristics/" target="_blank" rel="noreferrer">Jakob Nielsen：10 Usability Heuristics for User Interface Design</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/test-evaluate/" target="_blank" rel="noreferrer">W3C WAI：Evaluating Web Accessibility Overview</a>（访问日期：2026-07-17）</li></ul>`,74)])])}const b=i(e,[["render",t]]);export{c as __pageData,b as default};
